// S3A-002: 고객 세그먼테이션 — RFM 분석 엔진
// 90일 주문 데이터 + 회원 정보로 RFM 점수 계산 후 세그먼트 분류

const orderResp = $('최근 90일 주문 조회').first().json;
const memberResp = $('회원 조회').first().json;

const orders = orderResp.order || orderResp.list || [];
const members = memberResp.list || memberResp.user || [];

const now = new Date();
const today = $now.toFormat('yyyy-MM-dd');

// --- 회원 맵 구축 ---
const memberMap = {};
for (const m of members) {
  const uid = m.id || m.userid;
  if (uid) {
    memberMap[uid] = {
      user_name: m.hname || m.name || '',
      group_name: m.group_name || '일반',
      last_login: m.login_date || '',
      total_order_count: parseInt(m.order_count || 0)
    };
  }
}

// --- 주문 데이터를 고객별로 집계 ---
const customerData = {};

for (const order of orders) {
  const uid = order.userid;
  if (!uid) continue;

  if (!customerData[uid]) {
    customerData[uid] = {
      user_id: uid,
      orders: [],
      totalSpent: 0,
      orderCount: 0,
      lastOrderDate: null
    };
  }

  const c = customerData[uid];
  c.orderCount++;

  // 주문 금액 계산
  const baskets = order.basket || [];
  let orderTotal = 0;
  for (const item of baskets) {
    const price = parseInt(item.sell_price || item.price || 0);
    const qty = parseInt(item.quantity || item.ea || 1);
    orderTotal += price * qty;
  }
  c.totalSpent += orderTotal;

  // 최근 주문일
  const orderDate = order.order_date ? new Date(order.order_date) : null;
  if (orderDate && (!c.lastOrderDate || orderDate > c.lastOrderDate)) {
    c.lastOrderDate = orderDate;
  }
}

// --- RFM 점수 계산 ---
const customers = Object.values(customerData);

if (customers.length === 0) {
  return [{ json: { message: '⚠️ 분석 가능한 주문 데이터가 없습니다.', segments: [] } }];
}

// Recency: 마지막 주문일로부터 경과 일수
for (const c of customers) {
  c.recencyDays = c.lastOrderDate
    ? Math.floor((now - c.lastOrderDate) / (1000 * 60 * 60 * 24))
    : 999;
}

// 5분위 기준 계산 함수
function getQuintiles(arr) {
  const sorted = [...arr].sort((a, b) => a - b);
  const len = sorted.length;
  return [
    sorted[Math.floor(len * 0.2)],
    sorted[Math.floor(len * 0.4)],
    sorted[Math.floor(len * 0.6)],
    sorted[Math.floor(len * 0.8)]
  ];
}

// R 점수 (역방향: 적을수록 좋음)
const rValues = customers.map(c => c.recencyDays);
const rQ = getQuintiles(rValues);
function scoreR(days) {
  if (days <= rQ[0]) return 5;
  if (days <= rQ[1]) return 4;
  if (days <= rQ[2]) return 3;
  if (days <= rQ[3]) return 2;
  return 1;
}

// F 점수 (정방향: 많을수록 좋음)
const fValues = customers.map(c => c.orderCount);
const fQ = getQuintiles(fValues);
function scoreF(freq) {
  if (freq > fQ[3]) return 5;
  if (freq > fQ[2]) return 4;
  if (freq > fQ[1]) return 3;
  if (freq > fQ[0]) return 2;
  return 1;
}

// M 점수 (정방향: 많을수록 좋음)
const mValues = customers.map(c => c.totalSpent);
const mQ = getQuintiles(mValues);
function scoreM(monetary) {
  if (monetary > mQ[3]) return 5;
  if (monetary > mQ[2]) return 4;
  if (monetary > mQ[1]) return 3;
  if (monetary > mQ[0]) return 2;
  return 1;
}

// --- 세그먼트 분류 ---
function getSegment(r, f, m) {
  const avg = (r + f + m) / 3;
  if (r >= 4 && f >= 4 && m >= 4) return 'VIP';
  if (r >= 3 && f >= 3) return '충성고객';
  if (r >= 4 && f <= 2) return '신규고객';
  if (r >= 3 && avg >= 3) return '성장고객';
  if (r <= 2 && f >= 3) return '이탈위험';
  if (r <= 2 && f <= 2) return '휴면고객';
  return '일반고객';
}

// --- 결과 생성 ---
const segments = [];
const segmentCounts = {};

for (const c of customers) {
  const r = scoreR(c.recencyDays);
  const f = scoreF(c.orderCount);
  const m = scoreM(c.totalSpent);
  const segment = getSegment(r, f, m);

  const memberInfo = memberMap[c.user_id] || {};

  segments.push({
    user_id: c.user_id,
    user_name: memberInfo.user_name || '',
    group_name: memberInfo.group_name || '비회원',
    rfm_r: r,
    rfm_f: f,
    rfm_m: m,
    segment: segment,
    last_login: memberInfo.last_login || '',
    order_count: c.orderCount,
    total_spent: c.totalSpent,
    recency_days: c.recencyDays,
    updated_at: today
  });

  segmentCounts[segment] = (segmentCounts[segment] || 0) + 1;
}

// --- 텔레그램 메시지 ---
const fmt = (n) => n.toLocaleString('ko-KR');

let msg = '👥 <b>PRESSCO21 고객 세그먼테이션 리포트</b>\n';
msg += '━━━━━━━━━━━━━━━━━━\n';
msg += '📅 분석 기준: 최근 90일 (' + today + ')\n';
msg += '📊 분석 대상: ' + customers.length + '명\n\n';

msg += '🎯 <b>세그먼트 분포</b>\n';
const segOrder = ['VIP', '충성고객', '성장고객', '신규고객', '일반고객', '이탈위험', '휴면고객'];
for (const seg of segOrder) {
  const cnt = segmentCounts[seg] || 0;
  if (cnt === 0) continue;
  const pct = Math.round(cnt / customers.length * 100);
  let emoji = '📌';
  if (seg === 'VIP') emoji = '👑';
  else if (seg === '충성고객') emoji = '💎';
  else if (seg === '성장고객') emoji = '🌱';
  else if (seg === '신규고객') emoji = '🆕';
  else if (seg === '이탈위험') emoji = '⚠️';
  else if (seg === '휴면고객') emoji = '😴';
  msg += '  ' + emoji + ' ' + seg + ': ' + cnt + '명 (' + pct + '%)\n';
}

// VIP 상세
const vips = segments.filter(s => s.segment === 'VIP').sort((a,b) => b.total_spent - a.total_spent).slice(0, 5);
if (vips.length > 0) {
  msg += '\n👑 <b>VIP TOP 5</b>\n';
  vips.forEach((v, i) => {
    const name = v.user_name || v.user_id;
    msg += '  ' + (i+1) + '. ' + name + ' (' + v.group_name + ')\n';
    msg += '     ' + v.order_count + '건 / ' + fmt(v.total_spent) + '원\n';
  });
}

// 이탈위험 경보
const atRisk = segments.filter(s => s.segment === '이탈위험').sort((a,b) => b.total_spent - a.total_spent).slice(0, 5);
if (atRisk.length > 0) {
  msg += '\n⚠️ <b>이탈위험 고객 TOP 5 (재활성화 필요)</b>\n';
  atRisk.forEach((v, i) => {
    const name = v.user_name || v.user_id;
    msg += '  ' + (i+1) + '. ' + name + ' — ' + v.recency_days + '일 전 마지막 주문\n';
    msg += '     누적 ' + fmt(v.total_spent) + '원 / ' + v.order_count + '건\n';
  });
}

msg += '\n🤖 자동 생성 by n8n S3A-002';

return [{ json: { message: msg, segments: segments, summary: segmentCounts } }];
